import React, { useState } from 'react';

const JobListContainer = ({ appTheme = 'dark', limit }) => {
    // Data dummy 
    const [jobs] = useState([
        { id: 1, title: 'Fullstack Developer', company: 'PasukanYerusSolo', location: 'Solo (Remote)', salary: 'Rp 8.000.000', type: 'Full-time', category: 'IT', desc: 'Membangun arsitektur web modern menggunakan React & Laravel.' },
        { id: 2, title: 'React Frontend Engineer', company: 'TechEase Indonesia', location: 'Jakarta', salary: 'Rp 12.000.000', type: 'Remote', category: 'IT', desc: 'Fokus pada pengembangan antarmuka interaktif.' },
        { id: 3, title: 'Marketing Specialist', company: 'Solopos Group', location: 'Solo', salary: 'Rp 6.500.000', type: 'Full-time', category: 'Marketing', desc: 'Mengelola kampanye digital.' },
        { id: 4, title: 'Admin Operasional', company: 'Logistik Solo', location: 'Solo', salary: 'Rp 4.500.000', type: 'Contract', category: 'Administrasi', desc: 'Manajemen dokumentasi harian.' }
    ]);

    const [filter, setFilter] = useState('Semua');
    const displayJobs = (filter === 'Semua' ? jobs : jobs.filter(j => j.category === filter))
                        .slice(0, limit || jobs.length);

    return (
        <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
            {/* Filter */}
            <div style={{ marginBottom: '10px' }}>
                <select 
                    onChange={(e) => setFilter(e.target.value)}
                    style={{ padding: '8px', borderRadius: '8px', background: '#120b06', color: '#fff', border: '1px solid #262626' }}
                >
                    <option value="Semua">Semua Kategori</option>
                    <option value="IT">IT</option>
                    <option value="Marketing">Marketing</option>
                    <option value="Administrasi">Administrasi</option>
                </select>
            </div>

            {/* List Lowongan - Hanya satu map() disini */}
            {displayJobs.map(job => (
                <div key={job.id} style={{ 
                    padding: '20px', 
                    background: '#120b06', 
                    border: '1px solid #262626', 
                    borderRadius: '12px', 
                    transition: '0.3s' 
                }}>
                    <h3 style={{ color: '#fef3c7', fontSize: '16px', marginBottom: '4px' }}>{job.title}</h3>
                    <p style={{ color: '#ea580c', fontSize: '13px', fontWeight: '700', marginBottom: '10px' }}>{job.company}</p>
                    <div style={{ display: 'flex', gap: '15px', fontSize: '11px', color: '#a3a3a3' }}>
                        <span>📍 {job.location}</span>
                        <span>💰 {job.salary}</span>
                    </div>
                </div>
            ))}
        </div>
    );
};

export default JobListContainer;
